INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('488', '<p><strong>83. "ถั่วงอกมีข้อดีต่อเรามากมาย แต่ในขณะเดียวกันถั่วงอกก็มีอันตรายด้วย ซึ่งถั่วงอกจะมีสารที่ชื่อว่า ไฟเตต เมื่อสะสมอยู่ในร่างกาย ก็จะส่งผลเสียต่อร่างกาย การกำจัดสารนี้ควรนำไปต้มน้ำเดือดให้สุกก่อน หรือถ้าชอบรับประทานถั่วงอกดิบๆ ก็ควรระมัดระวังด้วย" ข้อใดคือสาระสำคัญ</strong></p>', '{"A":"ข้อดีข้อเสียของถั่วงอก","B":"อันตรายจากถั่วงอก","C":"วิธีรับประทานถั่วงอกที่ถูกต้อง","D":"ประโยชน์ของถั่วงอก"}', 'B', '<p><strong>ตอบ 2) อันตรายจากถั่วงอก</strong></p><p>แม้ตอนต้นบทความจะกล่าวถึงข้อดี แต่เนื้อหาหลักและจุดประสงค์ที่ผู้เขียนต้องการสื่อ เน้นไปที่การเตือนให้ระวังสารไฟเตตในถั่วงอกและข้อควรระวังในการรับประทาน สาระสำคัญจึงอยู่ที่อันตรายจากถั่วงอก</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('489', '<p><strong>84. "คุณพ่อ คุณแม่ ควรจะปลูกฝังลูกหลานให้รู้จักใช้รู้จักออม เพราะลูกจะได้เติบโตมาเป็นคนที่มีความสามารถในการจัดการด้านการเงินได้เป็นอย่างดีและรู้จักใช้รู้จักเก็บ ในเวลาที่จะใช้จ่ายในแต่ละครั้งนั้น จะทำให้เด็กรู้จักคุณค่าของเงินมากขึ้น การที่พ่อแม่จะสอนให้ลูกรู้จักการออม พ่อแม่ควรทำตัวให้เป็นแบบอย่างที่ดีก่อน เพราะการเป็นตัวอย่างที่ดีให้ลูกเห็น จะทำให้ลูกปฏิบัติตามง่ายขึ้น" ข้อใดสรุปไม่ถูกต้อง</strong></p>', '{"A":"พ่อแม่ควรเป็นแบบอย่างที่ดีให้ลูกปฏิบัติตาม","B":"พ่อแม่ควรเป็นนักออมที่ดี เพื่อให้ลูกปฏิบัติตามได้ง่ายขึ้น","C":"เด็กที่รู้จักใช้รู้จักออม จะเติบโตมาเป็นคนที่ร่ำรวย","D":"พ่อแม่ควรสอนให้ลูกรู้จักออมตั้งแต่เด็ก"}', 'C', '<p><strong>ตอบ 3) เด็กที่รู้จักใช้รู้จักออม จะเติบโตมาเป็นคนที่ร่ำรวย</strong></p><p>ในบทความระบุผลของการออมเพียงว่า "ลูกจะได้เติบโตมาเป็นคนที่มีความสามารถในการจัดการด้านการเงินได้เป็นอย่างดีและรู้จักใช้รู้จักเก็บ" ไม่ได้มีการกล่าวถึงหรือสรุปว่าจะทำให้ร่ำรวย ดังนั้นข้อ 3 จึงเป็นการสรุปที่เกินความจริงและไม่ถูกต้องตามบทความ</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('490', '<p><strong>85. "บรูไนเป็นประเทศที่มีประชากรน้อย ร้อยละ 75 ประกอบอาชีพข้าราชการ และอีกร้อยละ 25 ประกอบอาชีพเอกชนและพ่อค้า" ข้อใดไม่สอดคล้องกับบทความ</strong></p>', '{"A":"ชาวบรูไน \"ส่วนใหญ่\" เป็นข้าราชการ","B":"ชาวบรูไน \"เกือบทั้งหมด\" ไม่เป็นข้าราชการ","C":"ชาวบรูไน \"บางคน\" เป็นข้าราชการ","D":"ชาวบรูไน \"ส่วนน้อย\" ไม่ใช่ข้าราชการ"}', 'B', '<p><strong>ตอบ 2) ชาวบรูไน "เกือบทั้งหมด" ไม่เป็นข้าราชการ</strong></p><p>จากบทความระบุว่าชาวบรูไน ร้อยละ 75 ประกอบอาชีพข้าราชการ ซึ่งถือว่าเป็น "ส่วนใหญ่" การกล่าวว่าชาวบรูไน "เกือบทั้งหมดไม่เป็นข้าราชการ" จึงขัดแย้งและไม่สอดคล้องกับข้อมูลในบทความอย่างชัดเจน</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
